const App: React.FC = () => {
  const { language, t } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [scrolled, setScrolled] = useState(false);
  const mainRef = useRef<HTMLElement>(null);

  const [installPrompt, setInstallPrompt] = useState<any>(null);
  const [showIOSInstallPrompt, setShowIOSInstallPrompt] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => {
      setLoading(false);
    }, 4000);
    return () => clearTimeout(timer);
  }, []);

    useEffect(() => {
    const checkForNewMoviesAndNotify = async () => {
      if (!('Notification' in window) || Notification.permission !== 'granted' || !navigator.serviceWorker.ready) {
        return;
      }

      const registration = await navigator.serviceWorker.ready;
      const langCode = language === 'ku' ? 'ku' : 'en-US';
      const latestMovies = await fetchData(requests.fetchLatestMovies(langCode), language);

      if (!latestMovies || latestMovies.length === 0) return;

      const lastSeenLatest = JSON.parse(localStorage.getItem('lastSeenLatestMovies') || '[]');
      const lastSeenIds = new Set(lastSeenLatest.map((m: Content) => m.id));

      const newMovies = latestMovies.filter((m: Content) => !lastSeenIds.has(m.id));

      if (newMovies.length > 0) {
        const movie = newMovies[0];
        const title = t('newMovieTitle', { movieTitle: movie.title || movie.name || 'New Movie' });

        registration.showNotification(title, {
            body: t('newMovieBody', { movieTitle: movie.title || movie.name || '' }),
            icon: `${IMAGE_BASE_URL_POSTER}${movie.poster_path}`,
            badge: '/logo.svg',
            data: {
                url: `/#/details/${movie.media_type || 'movie'}/${movie.id}`
            }
        });
      }

      localStorage.setItem('lastSeenLatestMovies', JSON.stringify(latestMovies.slice(0, 10)));
    };

    // Run check after app is loaded to not interfere with startup
    if (!loading) {
      const checkTimeout = setTimeout(checkForNewMoviesAndNotify, 5000);
      return () => clearTimeout(checkTimeout);
    }
  }, [loading, language, t]);

  useEffect(() => {
    const mainEl = mainRef.current;
    if (!mainEl) return;

    const handleScroll = () => {
      setScrolled(mainEl.scrollTop > 10);
    };

    mainEl.addEventListener('scroll', handleScroll);
    handleScroll(); // Check on initial render

    return () => mainEl.removeEventListener('scroll', handleScroll);
  }, [loading]);

  useEffect(() => {
    const beforeInstallHandler = (e: Event) => {
        e.preventDefault();
        setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', beforeInstallHandler);

    const isIOS = () => /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
    const isInStandaloneMode = () => ('standalone' in window.navigator) && ((window.navigator) as any).standalone;

    if (isIOS() && !isInStandaloneMode()) {
        setShowIOSInstallPrompt(true);
    }

    return () => {
        window.removeEventListener('beforeinstallprompt', beforeInstallHandler);
    };
  }, []);

  const handleInstallClick = () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    installPrompt.userChoice.then(() => {
      setInstallPrompt(null);
    });
  };


  if (loading) {
    return <SplashScreen />;
  }

  return (
    <div className="bg-black min-h-screen text-white" dir={language === 'ku' ? 'rtl' : 'ltr'}>
      <HashRouter>
        <div className="flex">
          <Sidebar />
          <div className="flex-1 flex flex-col min-w-0">
            <Header scrolled={scrolled} />
            <main ref={mainRef} className="flex-1 overflow-y-auto">
              <Routes>
                <Route path="/" element={<HomePage />} />
                <Route path="/tv" element={<TVShowsPage />} />
                <Route path="/discover/:selection?" element={<DiscoverPage />} />
                <Route path="/studios" element={<StudiosListPage />} />
                <Route path="/studio/:id/:name" element={<StudioPage />} />
                <Route path="/details/:type/:id" element={<DetailPage />} />
                <Route path="/search" element={<SearchPage />} />
                <Route path="/my-list" element={<MyListPage />} />
              </Routes>
            </main>
          </div>
          <MobileNav />
        </div>
        <WelcomeNotificationPrompt />
        <AnimatePresence>
            {installPrompt && <DesktopInstallPrompt onInstall={handleInstallClick} onClose={() => setInstallPrompt(null)} />}
            {showIOSInstallPrompt && <IOSInstallPrompt onClose={() => setShowIOSInstallPrompt(false)} />}
        </AnimatePresence>
      </HashRouter>
    </div>
  );
};

export default App;

