import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Content, WatchProgress, MyListItem } from '../types';
import { fetchData } from '../services/tmdbService';
import { IMAGE_BASE_URL_POSTER } from '../constants';
import Spinner from './Spinner';
import { useTranslation } from '../contexts/LanguageContext';

interface RowProps {
  title: string;
  fetchUrl?: string;
  type?: 'movie' | 'tv';
  items?: (Content | WatchProgress | MyListItem)[];
}

const Row: React.FC<RowProps> = ({ title, fetchUrl, type, items }) => {
  const [content, setContent] = useState<(Content | WatchProgress | MyListItem)[]>([]);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);

  const navigate = useNavigate();
  const rowRef = useRef<HTMLDivElement>(null);
  const { language } = useTranslation();

  const loadInitialData = async () => {
    if (items) {
      setContent(items);
      setLoading(false);
      setHasMore(false); // Static items, no more to load
    } else if (fetchUrl) {
      setLoading(true);
      const data = await fetchData(`${fetchUrl}&page=1`, language);
      if (data && data.length > 0) {
        setContent(data);
        setPage(1);
        setHasMore(data.length === 20);
      } else {
        setContent([]);
        setHasMore(false);
      }
      setLoading(false);
    }
  };

  useEffect(() => {
    loadInitialData();
  }, [fetchUrl, items, language]);

  const handleScroll = useCallback(async () => {
    if (rowRef.current && fetchUrl && hasMore && !loadingMore) {
        const { scrollLeft, scrollWidth, clientWidth } = rowRef.current;
        const isNearEnd = scrollWidth - scrollLeft - clientWidth < 400;

        if (isNearEnd) {
            setLoadingMore(true);
            const nextPage = page + 1;
            const data = await fetchData(`${fetchUrl}&page=${nextPage}`, language);
            if (data && data.length > 0) {
                setContent(prev => [...prev, ...data]);
                setPage(nextPage);
                if (data.length < 20) setHasMore(false);
            } else {
                setHasMore(false);
            }
            setLoadingMore(false);
        }
    }
  }, [fetchUrl, hasMore, loadingMore, page, language]);

  const scroll = (direction: 'left' | 'right') => {
    if (rowRef.current) {
      const { scrollLeft, clientWidth } = rowRef.current;
      const scrollTo = direction === 'left' ? scrollLeft - clientWidth : scrollLeft + clientWidth;
      rowRef.current.scrollTo({ left: scrollTo, behavior: 'smooth' });
    }
  };

  if (loading) {
    return (
      <div className="h-60 flex items-center justify-center">
        <Spinner />
      </div>
    );
  }

  if (!content || content.length === 0) {
    return null;
  }

  return (
    <div className="mb-8 px-4 sm:px-6 lg:px-8">
      <h2 className="text-xl md:text-2xl font-bold mb-3 flex items-center">
        <span className="w-1 h-6 bg-red-600 mr-3 rtl:mr-0 rtl:ml-3"></span>
        {title}
      </h2>
      <div className="relative group">
        <button onClick={() => scroll('left')} className="absolute left-0 top-1/2 -translate-y-1/2 z-20 bg-black/50 hover:bg-black/80 p-2 rounded-full opacity-0 group-hover:opacity-100 transition duration-300 hidden md:block">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <div ref={rowRef} onScroll={handleScroll} className="flex overflow-x-scroll scrollbar-hide space-x-3 py-4">
          {content.map((item) => {
              const mediaType = (item as Content).media_type || (item as WatchProgress).type || type;
              if (!item.poster_path || !mediaType) return null;

              return (
              <motion.div
                key={item.id}
                onClick={() => navigate(`/details/${mediaType}/${item.id}`)}
                className="flex-shrink-0 w-36 md:w-48 group/item relative cursor-pointer transform transition-transform duration-200 hover:scale-105"
                whileTap={{ scale: 0.98 }}
              >
                <img
                  src={`${IMAGE_BASE_URL_POSTER}${item.poster_path}`}
                  alt={(item as Content).title || (item as Content).name}
                  className="rounded-md object-cover w-full h-full"
                />
                {'progress' in item && (
                    <>
                        <div className="absolute bottom-0 left-0 right-0 h-1.5 bg-gray-600 rounded-b-md">
                            <div className="h-full bg-red-600 rounded-b-md" style={{ width: `${((item as WatchProgress).progress / (item as WatchProgress).duration) * 100}%` }}></div>
                        </div>
                        {/* Show Season/Episode badge for TV shows in Continue Watching */}
                        {(item as WatchProgress).season && (
                            <div className="absolute top-2 right-2 bg-red-600/90 text-white text-[10px] font-bold px-1.5 py-0.5 rounded shadow-lg">
                                S{(item as WatchProgress).season} E{(item as WatchProgress).episode}
                            </div>
                        )}
                    </>
                )}
                 <div className="absolute inset-0 bg-black/30 opacity-0 group-hover/item:opacity-100 transition-opacity duration-300 rounded-md flex items-center justify-center">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-white/80" fill="currentColor" viewBox="0 0 20 20">
                        <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" />
                    </svg>
                 </div>
              </motion.div>
            )}
          )}
          {loadingMore && <div className="flex-shrink-0 w-36 md:w-48 flex items-center justify-center"><Spinner size="sm"/></div>}
        </div>
        <button onClick={() => scroll('right')} className="absolute right-0 top-1/2 -translate-y-1/2 z-20 bg-black/50 hover:bg-black/80 p-2 rounded-full opacity-0 group-hover:opacity-100 transition duration-300 hidden md:block">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>
    </div>
  );
};

