import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Clapperboard } from 'lucide-react';
import { fetchData } from '../services/tmdbService';
import { requests, IMAGE_BASE_URL, APP_VERSION } from '../constants';
import { Content } from '../types';

const SplashScreen: React.FC = () => {
  const [backgroundImage, setBackgroundImage] = useState<string | null>(null);

  useEffect(() => {
    let isMounted = true;
    const getBackgroundImage = async () => {
      try {
        // Generate a random page number between 1 and 3 to ensure variety
        const randomPage = Math.floor(Math.random() * 3) + 1;
        // Fetch latest popular action movies from the random page
        const data = await fetchData(requests.fetchLatestActionMovies('en-US', randomPage), 'en');

        if (isMounted && data && data.length > 0) {
          // Filter out movies that don't have a backdrop path
          const validMovies = data.filter((movie: Content) => movie.backdrop_path);

          if (validMovies.length > 0) {
            // Select randomly from all valid movies
            const randomMovie: Content = validMovies[Math.floor(Math.random() * validMovies.length)];

            if (randomMovie.backdrop_path) {
              const imageUrl = `${IMAGE_BASE_URL}${randomMovie.backdrop_path}`;
              const img = new Image();
              img.src = imageUrl;
              img.onload = () => {
                if (isMounted) setBackgroundImage(imageUrl);
              };
            }
          }
        }
      } catch (error) {
        console.error("Failed to fetch splash screen background:", error);
      }
    };
    getBackgroundImage();
    return () => { isMounted = false; };
  }, []);

  return (
    <motion.div
      exit={{ opacity: 0, scale: 1.1, filter: "blur(20px)" }}
      transition={{ duration: 0.8, ease: "easeInOut" }}
      className="fixed inset-0 bg-black flex flex-col items-center justify-center z-[200] overflow-hidden"
    >
      <AnimatePresence>
        {backgroundImage && (
          <motion.div
            key="bg"
            initial={{ opacity: 0, scale: 1.2 }}
            animate={{ opacity: 0.4, scale: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 2.5, ease: "easeOut" }}
            className="absolute inset-0"
          >
            <img 
              src={backgroundImage} 
              alt="" 
              className="w-full h-full object-cover grayscale opacity-60" 
            />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Heavy vignette overlay */}
      <div className="absolute inset-0 bg-gradient-to-b from-black via-black/90 to-black" />
      <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-transparent via-black/60 to-black opacity-80" />

      <div className="relative z-10 flex flex-col items-center justify-center px-4">
        {/* Logo Container */}
        <motion.div
            initial={{ scale: 0.8, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            transition={{ duration: 0.8, ease: [0.22, 1, 0.36, 1] }}
            className="relative mb-8"
        >
            <div className="absolute inset-0 bg-red-600 blur-[80px] opacity-30 rounded-full animate-pulse"></div>
            <div className="relative bg-gradient-to-br from-gray-900 to-black p-6 rounded-3xl border border-white/10 shadow-2xl ring-1 ring-white/5">
                 <Clapperboard className="w-16 h-16 md:w-24 md:h-24 text-red-600" strokeWidth={1.5} />
            </div>
        </motion.div>

        {/* Text Content */}
        <div className="text-center space-y-4">
            <motion.h1
                initial={{ y: 20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ delay: 0.3, duration: 0.8 }}
                className="text-5xl md:text-8xl font-black text-white tracking-tighter"
            >
                FLKRD
                <span className="text-red-600">.</span>
            </motion.h1>

            <motion.div
                initial={{ width: 0, opacity: 0 }}
                animate={{ width: "100%", opacity: 1 }}
                transition={{ delay: 0.6, duration: 0.8 }}
                className="h-[1px] bg-gradient-to-r from-transparent via-red-600/50 to-transparent w-full max-w-xs mx-auto"
            />

            <motion.p
                initial={{ opacity: 0, letterSpacing: "0.1em" }}
                animate={{ opacity: 1, letterSpacing: "0.3em" }}
                transition={{ delay: 0.8, duration: 1 }}
                className="text-xs md:text-sm text-gray-400 uppercase font-medium"
            >
                Unlimited Cinema
            </motion.p>
        </div>

        {/* Loading Indicator */}
        <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1, duration: 1 }}
            className="mt-16 w-32 md:w-48 h-0.5 bg-gray-900 rounded-full overflow-hidden"
        >
            <motion.div
                className="h-full bg-gradient-to-r from-red-600 to-red-400"
                initial={{ x: "-100%" }}
                animate={{ x: "100%" }}
                transition={{ repeat: Infinity, duration: 1.5, ease: "easeInOut" }}
            />
        </motion.div>
      </div>

      <div className="absolute bottom-8 w-full text-center">
         <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 0.6 }} 
            transition={{ delay: 1.5 }}
            className="flex flex-col items-center space-y-1"
         >
            <span className="text-[10px] text-white tracking-widest uppercase font-mono opacity-50">v{APP_VERSION}</span>
            <span className="text-xs text-red-500 font-medium tracking-wide">زانا فارۆۆق</span>
         </motion.div>
      </div>
    </motion.div>
  );
};

export default SplashScreen;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronLeft, Share, Play, X, AlertCircle, Check, Plus, VolumeX, Volume2, ChevronRight, Star } from 'lucide-react';
import { Content, WatchProgress, CastMember, MyListItem, SeasonDetails, SubtitleFile, SubtitleLine, Video, PlayerSource } from '../types';
import { fetchData, isForbidden } from '../services/tmdbService';
import { searchSubtitles, getSubtitleContent, parseSrt } from '../services/openSubtitlesService';
import { getRankedSources } from '../utils/playerSourceUtils';
import { API_KEY, IMAGE_BASE_URL_POSTER, IMAGE_BASE_URL, IMAGE_BASE_URL_LOGO, API_BASE_URL } from '../constants';
import Spinner from '../components/Spinner';
import Row from '../components/Row';
import { useTranslation } from '../contexts/LanguageContext';
import { useNotification } from '../contexts/NotificationContext';

type DetailTab = 'episodes' | 'subtitles' | 'similar' | 'details';

const DetailPage: React.FC = () => {
  const { type, id } = useParams<{ type: 'movie' | 'tv'; id: string }>();
  const [content, setContent] = useState<Content | null>(null);
  const [loading, setLoading] = useState(true);
  const [isPlayerLoading, setIsPlayerLoading] = useState(true);
  const [playerError, setPlayerError] = useState<string | null>(null);
  const [currentSeason, setCurrentSeason] = useState(1);
  const [currentEpisode, setCurrentEpisode] = useState(1);
  const [seasonDetails, setSeasonDetails] = useState<SeasonDetails | null>(null);
  const [cast, setCast] = useState<CastMember[]>([]);
  const [similar, setSimilar] = useState<Content[]>([]);
  const [isInMyList, setIsInMyList] = useState(false);

  const [rankedSources, setRankedSources] = useState<PlayerSource[]>([]);
  const [currentSourceIndex, setCurrentSourceIndex] = useState(0);

  const [activeTab, setActiveTab] = useState<DetailTab>(type === 'tv' ? 'episodes' : 'similar');

  const [trailerKey, setTrailerKey] = useState<string | null>(null);
  const [isPlayerModalOpen, setIsPlayerModalOpen] = useState(false);
  const [isSourceSelectorOpen, setIsSourceSelectorOpen] = useState(false);

  const [userRating, setUserRating] = useState<number>(0);
  const [hoverRating, setHoverRating] = useState<number>(0);

  const [availableSubtitles, setAvailableSubtitles] = useState<SubtitleFile[]>([]);
  const [activeSubtitle, setActiveSubtitle] = useState<SubtitleFile | null>(null);
  const [subtitleLines, setSubtitleLines] = useState<SubtitleLine[]>([]);
  const [isSubtitleLoading, setIsSubtitleLoading] = useState(false);
  const [subtitleError, setSubtitleError] = useState<string | null>(null);

  const playerRef = useRef<any>(null);
  const [trailerReady, setTrailerReady] = useState(false);
  const [isMuted, setIsMuted] = useState(true);


  const navigate = useNavigate();
  const { t, language } = useTranslation();
  const { addNotification } = useNotification();
  const langCode = language === 'ku' ? 'ku' : 'en-US';

  const playerLoadTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    setRankedSources(getRankedSources());
  }, []);

  useEffect(() => {
    if (!id) return;
    const myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    setIsInMyList(myList.some(item => item.id === Number(id)));

    // Load user rating with composite key to avoid collisions between movies/tv with same ID
    const ratings = JSON.parse(localStorage.getItem('flkrd_user_ratings') || '{}');
    const key = `${type}_${id}`;
    const currentRating = ratings[key];

    if (currentRating) {
        setUserRating(currentRating);
    } else {
        setUserRating(0); // Reset for new item
    }

  }, [id, type]);

  const fetchContentDetails = useCallback(async () => {
    if (!type || !id) return;
    setLoading(true);

    const findBestVideo = (videos: Video[] | undefined): Video | null => {
        if (!videos || videos.length === 0) return null;
        const youtubeVideos = videos.filter(v => v.site === 'YouTube');
        if (youtubeVideos.length === 0) return null;

        const priorities = ['Trailer', 'Teaser', 'Clip'];
        for (const priority of priorities) {
            const found = youtubeVideos.find(v => v.type === priority);
            if (found) return found;
        }

        return youtubeVideos[0];
    };

    try {
        const primaryEndpoint = `/${type}/${id}?api_key=${API_KEY}&language=${langCode}&append_to_response=credits,similar,videos`;
        const data = await fetchData(primaryEndpoint, language);

        if (data) {
            let allVideos: Video[] = data.videos?.results || [];

            if (allVideos.length === 0) {
                const allVideosEndpoint = `/${type}/${id}/videos?api_key=${API_KEY}`;
                const allVideosData = await fetchData(allVideosEndpoint, language);
                if (allVideosData?.results) {
                    allVideos = allVideosData.results;
                }
            }

            setContent(data);
            setCast(data.credits?.cast?.slice(0, 15) || []);
            const similarResults = data.similar?.results || [];
            setSimilar(similarResults.filter((item: Content) => !isForbidden(item, language)));
            setActiveTab(type === 'tv' ? 'episodes' : 'similar');

            const bestVideo = findBestVideo(allVideos);
            setTrailerKey(bestVideo ? bestVideo.key : null);

            searchSubtitles(id, type).then(setAvailableSubtitles);
        } else {
            setContent(null);
        }
    } catch (error) {
        console.error("Failed to fetch content details:", error);
        setContent(null);
    } finally {
        setLoading(false);
    }
  }, [type, id, langCode, language]);

  useEffect(() => {
    fetchContentDetails();
    const main = document.querySelector('main');
    if(main) main.scrollTo(0, 0);
  }, [fetchContentDetails]);

   useEffect(() => {
    const fetchSeasonData = async () => {
      if (type === 'tv' && id && currentSeason > 0) {
        const endpoint = `/tv/${id}/season/${currentSeason}?api_key=${API_KEY}&language=${langCode}`;
        const data = await fetchData(endpoint, language);
        setSeasonDetails(data);
      }
    };
    fetchSeasonData();
  }, [type, id, currentSeason, langCode, language]);

  // Save Progress Logic - Ensures cross-browser compatibility by saving on start
  const saveProgress = useCallback((currentTime: number = 0, duration: number = 0) => {
        if (!content || !type || !id) return;

        const progressData: WatchProgress = {
            id: Number(id),
            type: type,
            title: content.title || content.name || '',
            poster_path: content.poster_path,
            progress: currentTime,
            duration: duration,
            lastWatched: Date.now(),
            ...(type === 'tv' && { season: currentSeason, episode: currentEpisode })
        };

        try {
            const existingProgress: WatchProgress[] = JSON.parse(localStorage.getItem('watchProgress') || '[]');
            // Filter out existing entry for this specific item to avoid duplicates and push new one to top
            const filtered = existingProgress.filter(item => !(item.id === Number(id) && item.type === type));
            filtered.unshift(progressData); 
            // Keep max 20 items to avoid storage bloat
            if (filtered.length > 20) filtered.pop();

            localStorage.setItem('watchProgress', JSON.stringify(filtered));
            // Trigger storage event for other components (like HomePage) to update
            window.dispatchEvent(new Event('storage'));
        } catch (e) {
            console.error("Error saving progress", e);
        }
  }, [content, type, id, currentSeason, currentEpisode]);


  // YouTube Background Player Setup
  useEffect(() => {
    if (!trailerKey || !content) return;

    const onPlayerReady = (event: any) => {
      playerRef.current = event.target;
      event.target.playVideo();
      setTrailerReady(true);
    };

    const onPlayerStateChange = (event: any) => {
      // If the video ends or is paused by the browser, force it to play again.
      if (event.data === (window as any).YT.PlayerState.ENDED || event.data === (window as any).YT.PlayerState.PAUSED) {
          event.target.playVideo();
      }
    };

    const onPlayerError = (event: any) => {
        console.error("YouTube Player Error:", event.data);
    }

    const initPlayer = () => {
      if (playerRef.current) {
          try { playerRef.current.destroy(); } catch(e) {}
          playerRef.current = null;
      }
      playerRef.current = new (window as any).YT.Player('youtube-player', {
        videoId: trailerKey,
        playerVars: {
          autoplay: 1,
          mute: 1,
          controls: 0,
          showinfo: 0,
          modestbranding: 1,
          fs: 0,
          cc_load_policy: 0,
          iv_load_policy: 3,
          autohide: 1,
          rel: 0,
          playsinline: 1,
          loop: 1,
          playlist: trailerKey, // Required for loop to work
          origin: window.location.origin
        },
        events: {
          'onReady': onPlayerReady,
          'onStateChange': onPlayerStateChange,
          'onError': onPlayerError,
        },
      });
    };

    if (!(window as any).YT || !(window as any).YT.Player) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      if (document.querySelector('script[src="https://www.youtube.com/iframe_api"]')) {
          initPlayer();
      } else if (firstScriptTag && firstScriptTag.parentNode) {
          (window as any).onYouTubeIframeAPIReady = initPlayer;
          firstScriptTag.parentNode.insertBefore(tag, firstScriptTag);
      }
    } else {
      initPlayer();
    }

    return () => {
      if (playerRef.current && typeof playerRef.current.destroy === 'function') {
        try { playerRef.current.destroy(); } catch(e) {}
        playerRef.current = null;
      }
    };
  }, [trailerKey, content]);

  // Listener for iframe messages (best effort for progress updates)
  useEffect(() => {
    const handlePlayerMessage = (event: MessageEvent) => {
        const allowedOrigins = ['https://www.vidking.net', 'https://vidsrc.to', 'https://vidsrc.me', 'https://www.2embed.to', 'https://www.2embed.cc', 'https://superembed.stream', 'https://player.smashy.stream', 'https://moviesapi.club', 'https://vidsrc.pro', 'https://multiembed.mov'];
        // Allow all messages if origin is strictly not matching, but for security best practice we check list.
        // However, some providers might change subdomains.

        try {
            if (!event.data) return;
            // Parse message if it's a string
            const message = typeof event.data === 'string' ? JSON.parse(event.data) : event.data;

            if (message.type === 'PLAYER_EVENT' && message.data) {
                const { event: playerEvent, currentTime, duration } = message.data;
                if (playerEvent === 'timeupdate' && currentTime > 0) {
                     saveProgress(currentTime, duration);
                }
            }
        } catch (error) {}
    };
    window.addEventListener('message', handlePlayerMessage);
    return () => window.removeEventListener('message', handlePlayerMessage);
  }, [saveProgress]);

    const activePlayer = rankedSources[currentSourceIndex];
    let playerUrl = '';
    if (activePlayer && isPlayerModalOpen) {
        const vidkingParams = 'color=e50914&autoPlay=true';
        switch (activePlayer.name) {
            case 'Vidking':
                playerUrl = type === 'movie' ? `https://www.vidking.net/embed/movie/${id}?${vidkingParams}` : `https://www.vidking.net/embed/tv/${id}/${currentSeason}/${currentEpisode}?${vidkingParams}&nextEpisode=true&episodeSelector=true`;
                break;
            case 'Vidsrc.to':
                playerUrl = type === 'movie' ? `https://vidsrc.to/embed/movie/${id}` : `https://vidsrc.to/embed/tv/${id}/${currentSeason}/${currentEpisode}`;
                break;
            case 'Superembed':
                playerUrl = type === 'movie' ? `https://superembed.stream/movie?tmdb_id=${id}` : `https://superembed.stream/tv?tmdb_id=${id}&s=${currentSeason}&e=${currentEpisode}`;
                break;
            case 'VidSrc.pro':
                playerUrl = type === 'movie' ? `https://vidsrc.pro/embed/movie/${id}` : `https://vidsrc.pro/embed/tv/${id}/${currentSeason}/${currentEpisode}`;
                break;
            case 'SmashyStream':
                 playerUrl = type === 'movie' ? `https://player.smashy.stream/movie?tmdb=${id}` : `https://player.smashy.stream/tv?tmdb=${id}&s=${currentSeason}&e=${currentEpisode}`;
                 break;
            case 'MoviesAPI':
                playerUrl = type === 'movie' ? `https://moviesapi.club/movie/${id}` : `https://moviesapi.club/tv/${id}-${currentSeason}-${currentEpisode}`;
                break;
            case 'MultiEmbed':
                playerUrl = type === 'movie' ? `https://multiembed.mov/?video_id=${id}&tmdb=1` : `https://multiembed.mov/?video_id=${id}&tmdb=1&s=${currentSeason}&e=${currentEpisode}`;
                break;
            case 'Vidsrc.me':
                playerUrl = type === 'movie' ? `https://vidsrc.me/embed/movie?tmdb=${id}` : `https://vidsrc.me/embed/tv?tmdb=${id}&season=${currentSeason}&episode=${currentEpisode}`;
                break;
            case '2Embed':
                playerUrl = type === 'movie' ? `https://www.2embed.cc/embed/tmdb/movie?id=${id}` : `https://www.2embed.cc/embed/tmdb/tv?id=${id}&s=${currentSeason}&e=${currentEpisode}`;
                break;
        }
    }

    useEffect(() => {
        if(isPlayerModalOpen) {
            setIsPlayerLoading(true);
            setPlayerError(null);
        }
    }, [isPlayerModalOpen, currentSourceIndex]);

    useEffect(() => {
        if (!playerUrl || !isPlayerModalOpen) return;

        if (playerLoadTimeoutRef.current) clearTimeout(playerLoadTimeoutRef.current);

        playerLoadTimeoutRef.current = setTimeout(() => {
            setIsPlayerLoading(false);
            setPlayerError(t('playerSourceFailed'));
        }, 10000); // 10-second timeout

        return () => {
            if (playerLoadTimeoutRef.current) clearTimeout(playerLoadTimeoutRef.current);
        };
    }, [playerUrl, isPlayerModalOpen, t]);

    const handlePlayerLoad = () => {
        setIsPlayerLoading(false);
        setPlayerError(null);
        if (playerLoadTimeoutRef.current) clearTimeout(playerLoadTimeoutRef.current);
    };

    const handleSourceSelect = (index: number) => {
        setCurrentSourceIndex(index);
        setIsSourceSelectorOpen(false);
        setIsPlayerModalOpen(true);
        saveProgress(0, 0); // Save progress when switching source
    };

    const handlePlayClick = () => {
        const vidkingIndex = rankedSources.findIndex(s => s.name === 'Vidking');
        setCurrentSourceIndex(vidkingIndex >= 0 ? vidkingIndex : 0);
        setIsPlayerModalOpen(true);
        saveProgress(0, 0); // Save progress when clicking play
    };

    const handleSkipSource = () => {
        setCurrentSourceIndex(prevIndex => (prevIndex + 1) % rankedSources.length);
        saveProgress(0, 0);
    };

  const handleToggleMyList = () => {
    if (!content || !type) return;
    let myList: MyListItem[] = JSON.parse(localStorage.getItem('myList') || '[]');
    const contentIndex = myList.findIndex(item => item.id === content.id);
    if (contentIndex > -1) {
      myList.splice(contentIndex, 1);
      setIsInMyList(false);
      addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('myListRemoveSuccess') });
    } else {
      myList.push({ id: content.id, media_type: type, title: content.title || content.name || '', name: content.name, poster_path: content.poster_path });
      setIsInMyList(true);
      addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('myListAddSuccess') });
    }
    localStorage.setItem('myList', JSON.stringify(myList));
    window.dispatchEvent(new Event('storage'));
  };

  const handleShare = async () => {
    if (!content) return;
    const title = content.title || content.name || '';
    const text = `Check out ${title} on FLKRD MOVIES!`;
    const url = window.location.href;

    if (navigator.share) {
        try {
            await navigator.share({ title, text, url });
        } catch (error) {
            console.error('Error sharing:', error);
        }
    } else {
        navigator.clipboard.writeText(url).then(() => {
            addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('linkCopiedSuccess') });
        });
    }
  };

  const handleRating = (rating: number) => {
    if (!id || !type) return;
    setUserRating(rating);
    const ratings = JSON.parse(localStorage.getItem('flkrd_user_ratings') || '{}');
    const key = `${type}_${id}`;
    ratings[key] = rating;
    localStorage.setItem('flkrd_user_ratings', JSON.stringify(ratings));
    addNotification({ type: 'success', title: t('notificationsSuccessTitle'), message: t('ratingSaved') });
  };

  const handleLoadSubtitle = async (subtitle: SubtitleFile) => {
    if (activeSubtitle?.file_id === subtitle.file_id) {
        setActiveSubtitle(null);
        setSubtitleLines([]);
        return;
    }
    setActiveSubtitle(subtitle);
    setIsSubtitleLoading(true);
    setSubtitleError(null);
    setSubtitleLines([]);
    try {
        const content = await getSubtitleContent(subtitle.file_id);
        if (content) {
            setSubtitleLines(parseSrt(content));
        } else {
            setSubtitleError(t('subtitleLoadError'));
            addNotification({ type: 'error', title: t('notificationsErrorTitle'), message: t('subtitleError') });
        }
    } catch (error) {
        setSubtitleError(t('subtitleLoadError'));
        addNotification({ type: 'error', title: t('notificationsErrorTitle'), message: t('subtitleError') });
    } finally {
        setIsSubtitleLoading(false);
    }
  }

  const toggleMute = () => {
    if (!playerRef.current) return;
    if (isMuted) {
      playerRef.current.unMute();
    } else {
      playerRef.current.mute();
    }
    setIsMuted(!isMuted);
  };


  if (loading) {
    return <div className="min-h-screen flex items-center justify-center"><Spinner /></div>;
  }
  if (!content) {
    return <div className="min-h-screen flex items-center justify-center">{t('contentNotFound')}</div>;
  }

  const TabButton: React.FC<{tab: DetailTab, label: string}> = ({ tab, label }) => (
    <button
        onClick={() => setActiveTab(tab)}
        className={`py-2 px-1 text-base font-semibold transition-colors ${activeTab === tab ? 'text-white' : 'text-gray-400'}`}
    >
        {label}
        {activeTab === tab && <div className="mt-1 h-1 w-full bg-red-600 rounded-full"></div>}
    </button>
  );

  const truncate = (str: string | undefined, n: number) => {
    if (!str) return '';
    return str.length > n ? str.substr(0, n - 1) + '...' : str;
  };

  const SubtitleComponent = () => (
    <div className="space-y-4">
        {availableSubtitles.length > 0 ? (
            <div>
                <div className="flex items-center space-x-2 mb-4">
                    {availableSubtitles.map(sub => (
                        <button 
                            key={sub.file_id}
                            onClick={() => handleLoadSubtitle(sub)}
                            className={`px-4 py-2 rounded-md text-sm font-semibold transition-colors ${activeSubtitle?.file_id === sub.file_id ? 'bg-red-600 text-white' : 'bg-gray-800 hover:bg-gray-700 text-gray-300'}`}
                        >
                            {sub.language}
                        </button>
                    ))}
                </div>
                {isSubtitleLoading && <Spinner />}
                {subtitleError && !isSubtitleLoading && <p className="text-sm text-red-400 bg-red-900/20 p-3 rounded-md">{subtitleError}</p>}
                {subtitleLines.length > 0 && (
                    <div className="max-h-96 overflow-y-auto scrollbar-hide bg-black/50 p-3 rounded-md space-y-3 text-gray-300 text-center">
                        {subtitleLines.map(line => (
                            <p key={line.id} className="text-sm leading-relaxed">{line.text}</p>
                        ))}
                    </div>
                )}
            </div>
        ) : (
            <p className="text-gray-400">{t('noSubtitlesFound')}</p>
        )}
    </div>
  );

  return (
    <div className="pb-16 md:pb-0">
        <AnimatePresence>
            {isSourceSelectorOpen && (
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    className="fixed inset-0 bg-black/70 backdrop-blur-sm z-[100] flex items-center justify-center p-4"
                    onClick={() => setIsSourceSelectorOpen(false)}
                >
                    <motion.div
